import { Button } from '@material-ui/core';
import { FormControlLabel } from '@material-ui/core';
import { FormLabel } from '@material-ui/core';
import { RadioGroup } from '@material-ui/core';
import { Radio } from '@material-ui/core';
import React, { useRef } from 'react'
import { useState } from 'react';
import styled from 'styled-components'
import DoneIcon from '@material-ui/icons/Done';
import tile from '../../images/tile.png'
import FormSection from './FormSection';
import { useEffect } from 'react';
import LocalOfferIcon from '@material-ui/icons/LocalOffer';
import { db } from '../../components/firebase';
import { useDispatch, useSelector } from 'react-redux';
import { selectUser } from '../../features/userSlice';
import firebase from 'firebase'
import { selectError, showErrorIsTrue } from '../../features/errorSlice';
import { motion, useAnimation  } from 'framer-motion'
import { useInView } from 'react-intersection-observer';

export default function BuySection({lang}) {
    const user = useSelector(selectUser)
    const [value, setValue] = useState('basic')
    const [total, setTotal] = useState(0)
    const [domain, setDomain] = useState('')
    const [option, setOption] = useState('')
    const [email, setEmail] = useState('')
    const [message, setMessage] = useState('')
    const [name, setName] = useState(user ? user?.displayName : '')
    const [userEmail, setUserEmail] = useState(user ? user?.email : '')
    const [phone, setPhone] = useState('')
    const [terms, setTerms] = useState(false)
    const [payment, setPayment] = useState(false)
    const textRef = useRef(null)
    

    const [disabled, setDisabled] = useState(false)
    const dispatch = useDispatch()

    const handleRadioChange = (event, text) => {
        setValue(event.target.value || text);
    };

    const handleSubmit = (event) => {
        event.preventDefault();
        if (!user) {
            dispatch(selectError('Trebuie să te autentifici ❌'));
            dispatch(showErrorIsTrue())
            return
        }
        
        const random = Math.round(Math.random() * 1000)
        db.collection('cm-offers').doc(user?.email + random).set({
            name: name,
            email: userEmail,
            phone: phone,
            package: value,
            domain: domain,
            domainOp: option,
            businessEmail: email,
            message: message,
            onlinePayment: payment,
            total: Number(total),
            read: false,
            timestamp: firebase.firestore.FieldValue.serverTimestamp()
        })

        dispatch(selectError(`Ofertă trimisă✅`));
        dispatch(showErrorIsTrue())

        setName('')
        setUserEmail('')
        setPhone('')
        setMessage('')
        setEmail('')
        setDomain('')
        setOption('')
        setValue('basic')
        setPayment(false)
        setTerms(false)

        setDisabled(true)
    };

    useEffect(() => {
        let emailPrice = 0
        let price = +option
        if(email.length > 1) {
            emailPrice = 26 * 12
        }
        if (value === 'basic') {
            price += 100
        } else if (value === 'average') {
            price += 300
        } else {
            price += 1000
        }
        setTotal(price + emailPrice + (payment ? 500 : 0))
        return
    }, [value, option, email, payment])

    useEffect(() => {
        const elem = textRef.current.animate([
            {transform: 'scale(1.5)'},
            {color: "red"},
            {opacity: 0},
            ], {
               duration: 500,
               easing: "ease-in" 
            })
        return () => elem
    }, [total])


    const toForm = {
        name,
        setName,
        userEmail,
        setUserEmail,
        phone,
        setPhone,
        domain,
        setDomain,
        option,
        setOption,
        email,
        setEmail,
        message,
        setMessage,
        terms, 
        setTerms,
        payment,
        setPayment,
        lang
    }

    const controls = useAnimation();
    const { ref, inView } = useInView({
        "triggerOnce": true
    });

    useEffect(() => {
        if (inView) {
          controls.start('visible');
        }
        if (!inView) {
          controls.start('hidden');
        }
    }, [controls, inView]);

    
      const wrapperVariants = {
          hidden: {opacity: 0},
          visible: i => ({
              opacity: 1,
              transition: {
                  duration: 0.5,
                  delay: i * 0.2
              }
          })
      }

    return (
        <Container>
             <Form onSubmit={handleSubmit} ref={ref}>
                <MyFormLabel component="legend">{lang === "ro" ? "Alege Pachet" : "Choose Package"}</MyFormLabel>
                <MyRadioGroup aria-label="quiz" name="quiz" value={value} onChange={handleRadioChange}>
                    <Wrapper 
                    as={motion.div}
                    custom={1}
                    variants={wrapperVariants}
                    initial="hidden"
                    animate={controls}
                    onClick={e => handleRadioChange(e, 'basic')} 
                    className={value === 'basic' ? 'selected1 wrap1' : 'wrap1'}>
                        {lang === "ro" ?
                        <>
                        <FormControlLabel value="basic" 
                        control={<BasicRadio name="basic" />} 
                        label="Pachet Basic"/>
                        <Ul>
                            <Lig><DoneIcon/> Pagini: 1</Lig>
                            <Lig><DoneIcon/> Design responsive</Lig>
                            <Lig><DoneIcon/> Formular de contact pe email</Lig>
                            <Lig><DoneIcon/> Hosting gratuit</Lig>
                            <Lig><DoneIcon/> Optimizare SEO</Lig>
                        </Ul>
                        <Price>Preț: 100 RON</Price>
                        </>
                        :
                        <>
                        <FormControlLabel value="basic" 
                        control={<BasicRadio name="basic" />} 
                        label="Basic Package"/>
                        <Ul>
                            <Lig><DoneIcon/> Pages: 1</Lig>
                            <Lig><DoneIcon/> Responsive design</Lig>
                            <Lig><DoneIcon/> Email contact form</Lig>
                            <Lig><DoneIcon/> Free hosting</Lig>
                            <Lig><DoneIcon/> SEO</Lig>
                        </Ul>
                        <Price>Price: &euro; 20</Price>
                        </>
                        }
                    </Wrapper>
                    <Wrapper 
                    as={motion.div}
                    custom={0}
                    variants={wrapperVariants}
                    initial="hidden"
                    animate={controls}
                    onClick={e => handleRadioChange(e, 'average')} 
                    className={value === 'average' ? 'selected2 wrap2' : 'wrap2'}>
                        {lang === "ro" ?
                        <>
                        <FormControlLabel value="average" 
                        control={<AverageRadio name="average" />}
                        label="Pachet Basic Plus" />
                        <Ul>
                            <Lib><DoneIcon/> Pagini: 1 - 6</Lib>
                            <Lib><DoneIcon/> Design responsive</Lib>
                            <Lib><DoneIcon/> Formular de contact pe e-mail</Lib>
                            <Lib><DoneIcon/> Hosting gratuit</Lib>
                            <Lib><DoneIcon/> Optimizare SEO</Lib>
                        </Ul>
                        <Price>Preț: 300 RON</Price>
                        </>
                        :
                        <>
                        <FormControlLabel value="average" 
                        control={<AverageRadio name="average" />}
                        label="Basic Plus Package" />
                        <Ul>
                            <Lib><DoneIcon/> Pages: 1 - 6</Lib>
                            <Lib><DoneIcon/> Responsive design</Lib>
                            <Lib><DoneIcon/> Email contact form</Lib>
                            <Lib><DoneIcon/> Free hosting</Lib>
                            <Lib><DoneIcon/> SEO</Lib>
                        </Ul>
                        <Price>Price: &euro; 60</Price>
                        </>
                        }
                    </Wrapper>
                    <Wrapper 
                    as={motion.div}
                    custom={2}
                    variants={wrapperVariants}
                    initial="hidden"
                    animate={controls}
                    onClick={e => handleRadioChange(e, 'full')}
                    className={value === 'full' ? 'selected3 wrap3' : 'wrap3'}>
                        {lang === "ro" ? 
                        <>
                        <FormControlLabel value="full" 
                        control={<FullRadio name="full"/>} 
                        label="Pachet Full" />
                        <Ul>
                            <Lir><DoneIcon/> Pagini unice: 1 - 12</Lir>
                            <Lir><DoneIcon/> Design responsive</Lir>
                            <Lir><DoneIcon/> Formular de contact în website</Lir>
                            <Lir><DoneIcon/> Formular de contact pe e-mail</Lir>
                            <Lir><DoneIcon/> Review-uri clienți</Lir>
                            <Lir><DoneIcon/> Autentificare Google client/admin</Lir>
                            <Lir><DoneIcon/> Adăugare/ștergere produse</Lir>
                            <Lir><DoneIcon/> Încărcare imagini produse</Lir>
                            <Lir><DoneIcon/> Produse unice nelimitate</Lir>
                            <Lir><DoneIcon/> Hosting Gratuit</Lir>
                            <Lir><DoneIcon/> Optimizare SEO</Lir>
                            <Lir><DoneIcon/> Plata cu cardul (500 RON)</Lir>
                        </Ul>
                        <Price>Preț: 1000 RON</Price> 
                        </>
                        :
                        <>
                        <FormControlLabel value="full" 
                        control={<FullRadio name="full"/>} 
                        label="Full Package" />
                        <Ul>
                            <Lir><DoneIcon/> Unic Pages: 1 - 12</Lir>
                            <Lir><DoneIcon/> Responsive design</Lir>
                            <Lir><DoneIcon/> Contact form in website</Lir>
                            <Lir><DoneIcon/> Email contact form</Lir>
                            <Lir><DoneIcon/> Clients reviews</Lir>
                            <Lir><DoneIcon/> Client/Admin Authentication</Lir>
                            <Lir><DoneIcon/> Add/Delete products</Lir>
                            <Lir><DoneIcon/> Upload products images</Lir>
                            <Lir><DoneIcon/> Unic products: 50</Lir>
                            <Lir><DoneIcon/> Free hosting</Lir>
                            <Lir><DoneIcon/> SEO</Lir>
                            <Lir><DoneIcon/> Online card payment (&euro; 100)</Lir>
                        </Ul>
                        <Price>Price: &euro; 200</Price>
                        </>
                        }
                    </Wrapper>
                </MyRadioGroup>

                <FormSection valueFull={value} {...toForm}/>

                <BottomWrapper>
                    {lang === "ro" ? 
                        <TotalPrice ref={textRef}>Preț Total: <b>{total}</b> RON</TotalPrice> :
                        <TotalPrice ref={textRef}>Total Price: &euro; <b>{total / 5}</b></TotalPrice>
                    }
                    <Button 
                    disabled={disabled} 
                    type="submit" 
                    variant="contained" 
                    color="primary" 
                    endIcon={<LocalOfferIcon/>}>
                        {lang === "ro" ? "Trimite Ofertă" : "Send Offer"}
                    </Button>
                </BottomWrapper>
            </Form>
        </Container>
    )
}


const Container = styled.section`
    padding: 10px 0;
    background: linear-gradient(45deg, #0000001c 30%, transparent 30%), url(${tile});
`
const Form = styled.form`
    width: 1500px;
    max-width: 96vw;
    margin: 100px auto;
`
const MyFormLabel = styled(FormLabel)`
    font-size: var(--bf) !important;
    font-weight: 300 !important;
    color: #3a3a3a !important;
    font-family: var(--fsc) !important;
    position: relative !important;
    margin: 150px  0 100px 100px;
    &::after {
        position: absolute;
        content: '';
        bottom: -20px;
        left: 150px;
        width: 200px;
        height: 2px;
        background-color: var(--cbd);
    }
    @media screen and (max-width: 500px) {
        margin: 0 0 50px 20px;
        &::after {
            width: 150px;
        }
    }
`
const MyRadioGroup = styled(RadioGroup)`
    display: flex !important;
    flex-direction: row !important;
    justify-content: space-evenly;
    margin-bottom: 100px;
    flex-wrap: wrap;
    gap: 50px;
`
const Wrapper = styled.div`
    min-width: 250px;
    cursor: pointer;
    border: 5px solid lightgray;
    background: #ffffff;
    padding: 5px 20px 20px;
    border-radius: 10px;
    transition: all 0.5s ease-out;
    position: relative;
    color: lightgray;
    display: flex;
    flex-direction: column;
    flex-flow: column wrap;
    &::before {
        content: '';
        position: absolute;
        border-radius: 5px;
        width: 100%;
        z-index: 0;
        bottom: 0;
        left: 0;
        height: 0;
        transition: height 0.5s ease-out;
    }
    &.wrap1.selected1 {
        color: #3a3a3a;
        border-color: #84c219;
        &::before {
            height: 100%;
        }
    }
    &.wrap1::before {
        box-shadow: inset 0 0 10px #00000078;
        background-image: linear-gradient(45deg, #00c700 10%, #caffca 40%, #e4ffe4 40%, white 80%);
    }
    &.wrap2.selected2 {
        color: #3a3a3a;
        border-color: #2F85AD;
        &::before {
            height: 100%;
        }
    }
    &.wrap2::before {
        box-shadow: inset 0 0 10px #00000078;
        background-image: linear-gradient(45deg, #0068c9 10%, #cde7ff 40%, #d6ebff 40%, white 80%);
    }
    &.wrap3.selected3 {
        color: #3a3a3a;
        border-color: #AD2638;
        &::before {
            height: 100%;
        }
    }
    &.wrap3::before {
        box-shadow: inset 0 0 10px #00000078;
        background-color: #ffe2e2;
        background-image: linear-gradient(45deg, #df0000 10%, #ffcbcb 40%, #ffe2e2 40%, white 80%);
    }
    &::after {
        position: absolute;
        overflow: visible;
        content: '';
        bottom: -70px;
        left: 0;
        width: 100%;
        height: 30px;
        border-radius: 50%;
        background: radial-gradient(closest-side at 50%, #0000005a 10%, transparent);
        transition: all 0.5s ease-out;
        opacity: 0.5;
        @media screen and (max-width: 900px) {
            display: none;
        }
    }
    &:hover {
        transform: translateY(-10px);
        &::after {
            transform: translateY(10px);
            opacity: 0.3;
        }
    }
    >label {
        position: relative;
        z-index: 1;
        font-style: oblique;
        >span{
            font-weight: 600;
            font-size: var(--sf);
        }
    }
`
const BasicRadio = styled(Radio)`
    color: var(--cgd) !important;
`
const AverageRadio = styled(Radio)`
    color: var(--cbd) !important;
`
const FullRadio = styled(Radio)`
    color: var(--crd) !important;
`
const Ul = styled.ul`
    list-style: none;
    font-size: var(--xsf);
    position: relative;
    z-index: 1;
    font-weight: 500;
    >li {
        display: flex;
        align-items: center;
    } 
`
const Lig = styled.li`
    >svg {
        color: var(--cgd);
    }
`
const Lib = styled.li`
    >svg {
        color: var(--cbd);
    }
`
const Lir = styled.li`
    >svg {
        color: var(--crd);
    }
`
const Price = styled.span`
    z-index: 1;
    align-self: flex-end;
`
const BottomWrapper = styled.div`
    margin: 0 auto;
    width: 700px;
    max-width: 96vw;
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    >button {
        border-radius: 0px;
        background-color: #00000032;
        color: white;
        font-family: var(--fsss);
        &:hover {
            background-color: #00000099;
            animation: bounce 2s both;
            @keyframes bounce { 
                0%, 20%, 50%, 80%, 100% {
                    transform: translateY(0);
                } 
                40% {
                    transform: translateY(-5px);
                } 
                60% {
                    transform: translateY(-2px);
                } 
            }
        }
    }
`
const TotalPrice = styled.p`
    color: black;
    font-size: var(--sf);
    margin-bottom: 10px;
    position: relative;
    z-index: 1;
`