import React from 'react'
import { useEffect } from 'react'
import styled from 'styled-components'

export default function Cursor({cursor, outline}) {
    let text = "Site-ul tău ● reclama mea ● "
    text = text.split("")
    let deg = Math.ceil(360 / text.length)

    useEffect(() => {
        function cursorFunc(e) {
            cursor.current.style.top = e.pageY - 40 + 'px'
            cursor.current.style.left = e.pageX - 40 + 'px'
        }
        window.addEventListener('mousemove', cursorFunc)
        return () => window.removeEventListener('mousemove', cursorFunc)
    }, [cursor])



    return (
        <Container ref={cursor} className="cursor">
            <Wrapper className="cursor2">
            {text.map((txt, i) => (
                <span key={i} style={{height: 40 + 'px',  transform: 'rotate(' + deg * (i + 1) + 'deg)'}}>
                    {txt}
                </span>
            ))}
            </Wrapper>
            <Circle ref={outline} className="cursor3"/>
        </Container>
    )
}


const Container = styled.div`
    width: 80px;
    height: 80px;
    border-radius: 50%;
    border: 2px dotted black;
    mix-blend-mode: hue;
    position: absolute;
    z-index: 100;
    pointer-events: none;
    opacity: 1;
    transition: left .2s, top .2s, transform .5s, background-color .5s, opacity .5s !important;
    transition-timing-function: ease-in;
    &.onLink1 {
        opacity: 0;
    } 
    &.outLink1 {
        opacity: 1;
    }
    &.onLink2 {
        background-color: var(--cbl);
        transform: scale(1.5);
    } 
    &.outLink2 {
        background-color: transparent;
        transform: scale(1);
    }
    &.onLink3 {
        background-color: var(--crl);
        transform: scale(1.5);
    } 
    &.outLink3 {
        background-color: transparent;
        transform: scale(1);
    }
    &.onLink4 {
        transform: scale(0);
    } 
    &.outLink4 {
        transform: scale(1);
    }
    @media screen and (max-width: 500px) {
        display: none;
    }
`
const Wrapper = styled.div`
    width: 100%;
    height: 100%;
    border-radius: 50%;
    text-align: center;
    transform-origin: center;
    position: relative;
    animation: spin 5s infinite linear;
    @keyframes spin {
        to {
            transform: rotate(360deg);
        }
    }
    >span {
        display: inline-block;
        font-family: var(--fsss);
        color: black;
        font-size: 10px;
        font-weight: 500;
        position: absolute;
        transform-origin: 0 100%;
    }
`
const Circle = styled.div`
    position: absolute;
    inset: 0;
    transform: scale(0);
    border-radius: 50%;
    opacity: 0;
    transition: all .5s!important;
    transition-timing-function: ease-in;
    &.onCircle {
        border: 1px solid var(--cbl);
        opacity: 1;
        transform: scale(3);
    } 
    &.outCircle {
        border: 1px solid transparent;
        opacity: 0;
        transform: scale(0);
    }
    &.onBubble {
        border: 1px solid var(--cgl);
        opacity: 1;
        transform: scale(3);
    } 
    &.outBubble {
        border: 1px solid transparent;
        opacity: 0;
        transform: scale(0);
    }
`