import styled from 'styled-components';
import { Link } from 'react-router-dom';
import FacebookIcon from '@material-ui/icons/Facebook';
import TwitterIcon from '@material-ui/icons/Twitter';
import YouTubeIcon from '@material-ui/icons/YouTube';
import GitHubIcon from '@material-ui/icons/GitHub';
import logo from '../images/codmitu.svg'
import cards from '../images/logos/cards.png'
import PhoneIphoneIcon from '@material-ui/icons/PhoneIphone';
import AlternateEmailIcon from '@material-ui/icons/AlternateEmail';
import MyLocationIcon from '@material-ui/icons/MyLocation';

export default function Footer({lang}) {
    return (
        <FooterContainer>
            <FooterWrapper>
                <Wrapper>
                    <Left>
                        <FooterLinkTitle>{lang === "ro" ? "Linkuri Client" : "Client Links"}</FooterLinkTitle>
                        <MyLink href="https://anpc.ro/?ref=footer_3_5" target="_blank">{lang === "ro" ? "Reclamație - ANPC" : "Make a complaint - NACP"}</MyLink>
                        <FooterLink to="/termeni-si-conditii">{lang === "ro" ? "Termeni și Condiții" : "Terms and Conditions"}</FooterLink>
                        <FooterLink to="/politica-de-confidentialitate">{lang === "ro" ? "Politica de Confidențialitate" : "Privacy Policy"}</FooterLink>
                    </Left>
                    <Center>
                        <FooterLinkTitle>{lang === "ro" ? "Linkuri Interne" : "Internal Links"}</FooterLinkTitle>
                        <FooterLink onClick={() => window.scrollTo(0, 0)} to="">{lang === "ro" ? "acasă" : "home"}</FooterLink>
                        <FooterLink onClick={() => window.scrollTo(0, 0)} to="/cumpara">{lang === "ro" ? "cumpără" : "buy"}</FooterLink>
                    </Center>
                    <Right>
                        <Contact>
                            <P>+40 746 960 443 <PhoneIphoneIcon/></P>
                            <P>codmitu@gmail.com <AlternateEmailIcon/></P>
                            <P>Romania ∣ Timisoara ∣ 300553 <MyLocationIcon/></P>
                        </Contact>
                        <Cards src={cards} alt="cards allowed"/>
                    </Right>
                </Wrapper>
               
                <SocialMedia>
                    <SocialMediaWrapper>
                        <SocialLogo onClick={() => window.scrollTo(0, 0)} to="">
                            <img src={logo} alt="logo"/>
                        </SocialLogo>
                        <WebsiteRights>codmitu.com &copy;{new Date().getFullYear()} {lang === "ro" ? "Toate drepturile rezervate." : "All rights reserved."}</WebsiteRights>
                        <SocialIcons>
                            <SocialIconLink href="https://www.facebook.com/profile.php?id=100069009977273" target="_blank" aria-label="Facebook">
                                <FacebookIcon />
                            </SocialIconLink>
                            <SocialIconLink href="https://www.youtube.com/channel/UCcevIRmsh-gsiPWw7z45cog" target="_blank" aria-label="Youtube">
                                <YouTubeIcon />
                            </SocialIconLink>
                            <SocialIconLink href="https://twitter.com/codmitu" target="_blank" aria-label="Twitter">
                                <TwitterIcon />
                            </SocialIconLink>
                            <SocialIconLink href="https://github.com/codmitu" target="_blank" aria-label="Github">
                                <GitHubIcon />
                            </SocialIconLink>
                            <SocialIconLink href="https://codepen.io/codmitu" target="_blank" aria-label="Codepen">
                                <span className="iconify" data-icon="fe:codepen"></span>
                            </SocialIconLink>
                        </SocialIcons>
                    </SocialMediaWrapper>
                </SocialMedia>
            </FooterWrapper>
        </FooterContainer>
    )
}






const FooterContainer = styled.footer`
    background-color: #f5f5f5;
`
const FooterWrapper = styled.div`
    padding: 48px 0;
    gap: 30px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    max-width: 1100px;
    margin: 0 auto;
`
const Wrapper = styled.div`
    display: flex;
    justify-content: space-around;
    width: 100%;
    border-bottom: 1px solid lightgray;
    @media screen and (max-width: 600px) {
        flex-flow: column wrap;
    }
`
const Left = styled.div`
    display: flex;
    flex-direction: column;
    align-items: left;
    margin: 1rem;
    color: black;
    >* {
        white-space: nowrap;
    }
    @media screen and (max-width: 600px) {
        align-self: flex-start;
    }
`
const FooterLinkTitle = styled.h1`
    font-size: 0.8rem;
    margin-bottom: 0.5rem;
`
const MyLink = styled.a`
    all: unset;
    list-style: none;
    overflow: hidden;
    position: relative;
    padding: 5px 0;
    font-size: 0.8rem;
    text-decoration: none;
    color: black;
    width: max-content;
    cursor: pointer;
    &::after {
        content: '';
        position: absolute;
        width: 100%;
        height: 1px;
        background-color: var(--cbl);
        bottom: 0px;
        left: -100%;
        z-index: 2;
        transition: .5s ease;
    }
    &:hover::after {
        left: 0;
    }
`
const FooterLink = styled(Link)`
    list-style: none;
    overflow: hidden;
    position: relative;
    padding: 5px 0;
    font-size: 0.8rem;
    text-decoration: none;
    color: black;
    width: max-content;
    &::after {
        content: '';
        position: absolute;
        width: 100%;
        height: 1px;
        background-color: var(--cbl);
        bottom: 0px;
        left: -100%;
        z-index: 2;
        transition: .5s ease;
    }
    &:hover::after {
        left: 0;
    }
`
const Center = styled.div`
    display: flex;
    flex-direction: column;
    /* align-items: flex-start; */
    margin: 1rem;
    color: black;
    >* {
        white-space: nowrap;
    }
    @media screen and (max-width: 600px) {
        align-self: center;
    }
`
const Right = styled.div`
    display: flex;
    align-items: flex-end;
    flex-direction: column;
    margin: 1rem;
    @media screen and (max-width: 600px) {
        align-self: flex-end;
    }
`
const Contact = styled.div`
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    margin-bottom: 20px;
`
const P = styled.p`
    display: flex;
    align-items: center;
    font-size: 0.8rem;
    >svg {
        font-size: 1rem;
        margin-left: 5px;
    }
`
const Cards = styled.img`
    width: 150px;
`
const SocialMedia = styled.section`
    max-width: 1000px;
    width: 100%;
`
const SocialMediaWrapper = styled.div`
    padding: 0 10px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    max-width: 1100px;
    @media screen and (max-width: 820px) {
        flex-direction: column;
    }
`
const SocialLogo = styled(Link)`
    cursor: pointer;
    text-decoration: none;
    flex: 0.3;
    >img {
        height: 70px;
    }
`
const WebsiteRights = styled.small`
    color: #242424;
    flex: 0.3;
    text-align: center;
    @media screen and (max-width: 820px) {
        margin-bottom: 20px;
    }
`
const SocialIcons = styled.div`
    flex: 0.3;
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 240px;
`
const SocialIconLink = styled.a`
    color: #313131;
    font-size: 24px;
    &[aria-label="Facebook"] {
        &:hover {
            color: #4064ac;
        }
    }
    &[aria-label="Youtube"] {
        &:hover {
            color: #f70000;
        }
    }
    &[aria-label="Twitter"] {
        &:hover {
            color: #1d9ce9;
        }
    }
    &[aria-label="Github"] {
        &:hover {
            color: #a200ff;
        }
    }
    &[aria-label="Codepen"] {
        &:hover {
            color: #6d6d6d;
        }
    }
`
