import { useEffect } from 'react'

export const useMotion = ({ inview, controls }) => {

    useEffect(() => {
        if (inview) {
            controls.start('visible');
        }
        if (!inview) {
            controls.start('hidden');
        }
    }, [controls, inview]);

    const imageVariants = {
        hidden: { y: 300, opacity: 0 },
        visible: {
            y: 0,
            opacity: 1,
            transition: {
                duration: 1,
                ease: "easeOut"
            }
        }
    }

    const listVariants = {
        hidden: { y: 200, opacity: 0 },
        visible: i => ({
            y: 0,
            opacity: 1,
            transition: {
                duration: 0.5,
                delay: (i * 0.1) + 0.5
            }
        })
    }

    return { imageVariants, listVariants }
}
